const raw = $json.text;

let data;

try {
  data = JSON.parse(raw);
} catch (error) {
  data = {
    name: "",
    email: "",
    phone: "",
    interest: "",
    intent: "irrelevant",
    priority: "cold",
    recommended_action: "Manual review required"
  };
}

return [
  {
    json: data
  }
];

const newLead = $('Code in JavaScript').first().json;
const existingLeads = $input.all().map(item => item.json);

const clean = (value) => {
  return String(value || "")
    .toLowerCase()
    .replace(/\s/g, "")
    .trim();
};

const duplicate = existingLeads.find(lead => {
  const sameEmail =
    clean(newLead.email) !== "" &&
    clean(lead.email_from) !== "" &&
    clean(newLead.email) === clean(lead.email_from);

  const samePhone =
    clean(newLead.phone) !== "" &&
    clean(lead.phone) !== "" &&
    clean(newLead.phone) === clean(lead.phone);

  return lead.type === "opportunity" && (sameEmail || samePhone);
});

return [
  {
    json: {
      ...newLead,
      isDuplicate: duplicate ? true : false,
      duplicateId: duplicate ? duplicate.id : null,
      matchedEmail: duplicate ? duplicate.email_from : null,
      matchedPhone: duplicate ? duplicate.phone : null
    }
  }
];
